class Exports {
    String packageJson;
    List<dynamic> empty;
    Helpers helpers;
    Browser browser;
    List<dynamic> yargs;

    Exports({
        required this.packageJson,
        required this.empty,
        required this.helpers,
        required this.browser,
        required this.yargs,
    });

    factory Exports.fromJson(Map<String, dynamic> json) => Exports(
        packageJson: json["./package.json"],
        empty: List<dynamic>.from(json["."].map((x) => x)),
        helpers: Helpers.fromJson(json["./helpers"]),
        browser: Browser.fromJson(json["./browser"]),
        yargs: List<dynamic>.from(json["./yargs"].map((x) => x)),
    );

    Map<String, dynamic> toJson() => {
        "./package.json": packageJson,
        ".": List<dynamic>.from(empty.map((x) => x)),
        "./helpers": helpers.toJson(),
        "./browser": browser.toJson(),
        "./yargs": List<dynamic>.from(yargs.map((x) => x)),
    };
}

